
import { formatDate } from './date';

export function formatInteractionForClipboard(interaction) {
    const date = formatDate(interaction.timestamp);


    const url = `${window.location.origin}/history/${interaction.id}`;

    return `${date} ${interaction.model}\n${url}\n\n${interaction.response}`;
}

export async function copyToClipboard(text) {
    try {
        await navigator.clipboard.writeText(text);
        return true;
    } catch (err) {
        console.error('Failed to copy: ', err);
        return false;
    }
}
