<template>
  <div class="bg-white dark:bg-gray-800 shadow overflow-hidden sm:rounded-lg">
    <div class="px-4 py-5 sm:px-6">
      <h3 class="text-lg leading-6 font-medium text-gray-900 dark:text-gray-100">
        Saved Templates
      </h3>
      <p class="mt-1 max-w-2xl text-sm text-gray-500 dark:text-gray-400">
        Select a template to load its configuration into the Generate view.
      </p>
    </div>
    <div class="border-t border-gray-200 dark:border-gray-700">
      <div v-if="loading" class="text-center py-4">
        <p class="text-sm text-gray-500 dark:text-gray-400">Loading templates...</p>
      </div>
      <div v-else-if="templates.length === 0" class="text-center py-4">
        <p class="text-sm text-gray-500 dark:text-gray-400">No templates found.</p>
      </div>
      <ul v-else role="list" class="divide-y divide-gray-200 dark:divide-gray-700">
        <li v-for="template in templates" :key="template.id">
          <a @click="selectTemplate(template)" class="block hover:bg-gray-50 dark:hover:bg-gray-700 cursor-pointer">
            <div class="px-4 py-4 sm:px-6">
              <div class="flex items-center justify-between">
                <p class="text-sm font-medium text-indigo-600 dark:text-indigo-400 truncate">
                  {{ template.name }}
                </p>
                <div class="ml-2 flex-shrink-0 flex">
                  <p class="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-green-100 dark:bg-green-900 text-green-800 dark:text-green-200">
                    {{ template.model }}
                  </p>
                </div>
              </div>
              <div class="mt-2 sm:flex sm:justify-between">
                <div class="sm:flex">
                  <p class="flex items-center text-sm text-gray-500 dark:text-gray-400">
                    Created by {{ template.creator }}
                  </p>
                </div>
                <div class="mt-2 flex items-center text-sm text-gray-500 dark:text-gray-400 sm:mt-0">
                  <p>
                    {{ formatDate(template.createdAt) }}
                  </p>
                </div>
              </div>
            </div>
          </a>
        </li>
      </ul>
    </div>
    <div v-if="error" class="px-4 py-2 text-sm text-red-600 dark:text-red-400">
        {{ error }}
    </div>
  </div>
</template>

<script>
import { db } from '../firebase';
import { collection, query, orderBy, getDocs } from 'firebase/firestore';

export default {
  name: 'Templates',
  data() {
    return {
      templates: [],
      loading: true,
      error: null
    }
  },
  async mounted() {
    await this.fetchTemplates();
  },
  methods: {
    async fetchTemplates() {
      try {
        const q = query(collection(db, "templates"), orderBy("createdAt", "desc"));
        const querySnapshot = await getDocs(q);
        this.templates = querySnapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        }));
      } catch (e) {
        console.error("Error fetching templates:", e);
        this.error = "Failed to load templates.";
      } finally {
        this.loading = false;
      }
    },
    formatDate(timestamp) {
      if (!timestamp) return '';
      return new Date(timestamp.seconds * 1000).toLocaleDateString() + ' ' + new Date(timestamp.seconds * 1000).toLocaleTimeString();
    },
    selectTemplate(template) {
        this.$router.push({
            name: 'Generate',
            params: { templateData: template }
        });
    }
  }
}
</script>
