
const FOLDER_ID = '11biMhJA1Ztoc7r2SPurrIftcR87ep39m';

/**
 * Calculates SHA-256 hash of a File object
 * @param {File} file 
 * @returns {Promise<string>} Hex string of hash
 */
async function calculateHash(file) {
    const arrayBuffer = await file.arrayBuffer();
    const hashBuffer = await crypto.subtle.digest('SHA-256', arrayBuffer);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
    console.log("[Drive] Hash calculated:", hashHex);
    return hashHex;
}

/**
 * Searches for a file with the given name (hash) in the target folder
 * @param {string} name 
 * @param {string} accessToken 
 * @returns {Promise<Object|null>} File metadata or null
 */
async function findFileByName(name, accessToken) {
    console.log("[Drive] Searching for file:", name);
    const query = `name = '${name}' and '${FOLDER_ID}' in parents and trashed = false`;
    const url = `https://www.googleapis.com/drive/v3/files?q=${encodeURIComponent(query)}&fields=files(id, name, webContentLink, webViewLink, thumbnailLink, mimeType)&pageSize=1`;

    try {
        const response = await fetch(url, {
            headers: { 'Authorization': `Bearer ${accessToken}` }
        });
        if (!response.ok) throw new Error(`Failed to search Drive: ${response.status} ${response.statusText}`);
        const data = await response.json();
        return data.files && data.files.length > 0 ? data.files[0] : null;
    } catch (e) {
        console.error("Error searching file:", e);
        throw e;
    }
}

/**
 * Uploads a file to the target Google Drive folder
 * @param {File} file 
 * @param {string} name (The hash)
 * @param {string} accessToken 
 * @returns {Promise<Object>} Uploaded file metadata
 */
async function uploadToDrive(file, name, accessToken) {
    const metadata = {
        name: name,
        parents: [FOLDER_ID],
        mimeType: file.type
    };

    const form = new FormData();
    form.append('metadata', new Blob([JSON.stringify(metadata)], { type: 'application/json' }));
    form.append('file', file);

    const url = 'https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart&fields=id,name,webContentLink,webViewLink,thumbnailLink';

    try {
        console.log("[Drive] Starting multipart upload...");
        const response = await fetch(url, {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${accessToken}` },
            body: form
        });

        if (!response.ok) {
            const err = await response.text();
            throw new Error(`Upload failed: ${err}`);
        }

        const data = await response.json();
        console.log("[Drive] Upload success, metadata:", data);

        // Make formatted public (Anyone with link can read)
        try {
            await makePublic(data.id, accessToken);
            console.log("[Drive] Permissions updated to public");
        } catch (permErr) {
            console.warn("[Drive] Failed to set public permissions (non-fatal):", permErr);
        }

        return data;
    } catch (e) {
        console.error("[Drive] Error uploading file:", e);
        throw e;
    }
}

/**
 * Sets permission to anyone with link = reader
 * @param {string} fileId 
 * @param {string} accessToken 
 */
async function makePublic(fileId, accessToken) {
    const url = `https://www.googleapis.com/drive/v3/files/${fileId}/permissions`;
    const body = {
        role: 'reader',
        type: 'anyone'
    };

    await fetch(url, {
        method: 'POST',
        headers: {
            'Authorization': `Bearer ${accessToken}`,
            'Content-Type': 'application/json'
        },
        body: JSON.stringify(body)
    });
}

/**
 * Main entry point to process a file
 * @param {File} file 
 * @param {string} accessToken 
 * @returns {Promise<Object>} { webContentLink, webViewLink, id, name, type }
 */
export async function processFile(file, accessToken) {
    if (!accessToken) throw new Error("No access token provided");

    // 1. Calculate Hash
    console.log("[Drive] Processing file:", file.name);
    const hash = await calculateHash(file);

    // 2. Check existence
    let driveFile = await findFileByName(hash, accessToken);

    if (driveFile) {
        console.log("File found in Drive (Deduplication):", driveFile);
    } else {
        console.log("[Drive] File not found, uploading...");
        // 3. Upload if new
        driveFile = await uploadToDrive(file, hash, accessToken);
        console.log("[Drive] Upload procedure complete:", driveFile);
    }

    return {
        ...driveFile,
        originalName: file.name,
        type: file.type
    };
}
