<template>
  <div class="bg-white dark:bg-gray-800 shadow sm:rounded-lg">
    <div class="px-4 py-5 sm:p-6">
      <h3 class="text-lg leading-6 font-medium text-gray-900 dark:text-gray-100 mb-4">
        Interaction History
      </h3>
      
      <div class="mb-4 flex flex-col sm:flex-row gap-4 items-center justify-between">
         <div class="flex items-center space-x-4">
            <label class="flex items-center space-x-2 text-sm text-gray-700 dark:text-gray-300">
                <input type="checkbox" v-model="filters.starredOnly" class="rounded border-gray-300 text-indigo-600 shadow-sm focus:border-indigo-300 focus:ring focus:ring-indigo-200 focus:ring-opacity-50">
                <span>Starred Only</span>
            </label>
             <label class="flex items-center space-x-2 text-sm text-gray-700 dark:text-gray-300">
                <input type="checkbox" v-model="filters.includeHidden" class="rounded border-gray-300 text-indigo-600 shadow-sm focus:border-indigo-300 focus:ring focus:ring-indigo-200 focus:ring-opacity-50">
                <span>Include Hidden</span>
            </label>
         </div>
         <div class="w-full sm:w-64">
             <input type="text" v-model="filters.search" placeholder="Search title, user, model..." class="shadow-sm focus:ring-indigo-500 focus:border-indigo-500 block w-full sm:text-sm border-gray-300 rounded-md dark:bg-gray-700 dark:text-white dark:placeholder-gray-400">
         </div>
      </div>
      
      <div v-if="loading && interactions.length === 0" class="text-gray-500 dark:text-gray-400 text-sm">
        Loading...
      </div>
      
      <div v-else-if="filteredInteractions.length === 0" class="text-gray-500 dark:text-gray-400 text-sm">
        No interactions found.
      </div>
      
      <div v-else class="flex flex-col">
        <div class="-my-2 overflow-x-auto sm:-mx-6 lg:-mx-8">
          <div class="py-2 align-middle inline-block min-w-full sm:px-6 lg:px-8">
            <div class="shadow overflow-hidden border-b border-gray-200 dark:border-gray-700 sm:rounded-lg">
              <table class="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
                <thead class="bg-gray-50 dark:bg-gray-700">
                  <tr>
                    <th scope="col" class="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider w-32">
                      <!-- Actions -->
                    </th>
                    <th scope="col" class="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider w-32">
                      Date
                    </th>
                    <th scope="col" class="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider w-24">
                      Cost
                    </th>
                    <th scope="col" class="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider w-32">
                      User
                    </th>
                     <th scope="col" class="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider w-24">
                      Model
                    </th>
                    <th scope="col" class="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">
                      Title
                    </th>
                  </tr>
                </thead>
                <tbody class="bg-white dark:bg-gray-800 divide-y divide-gray-200 dark:divide-gray-700">
                  <tr v-for="item in filteredInteractions" :key="item.id" :class="{'opacity-50': item.hidden}">
                    <td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-400">
                         <div class="flex items-center space-x-3">
                            <router-link :to="'/history/' + item.id" class="text-indigo-600 dark:text-indigo-400 hover:text-indigo-900 dark:hover:text-indigo-300" title="View">
                                <svg class="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                                </svg>
                            </router-link>
                            <button @click="toggleStar(item)" class="focus:outline-none" title="Star">
                                <svg v-if="item.starred" class="h-5 w-5 text-yellow-400" viewBox="0 0 20 20" fill="currentColor">
                                    <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                                </svg>
                                <svg v-else class="h-5 w-5 text-gray-300 hover:text-yellow-400" viewBox="0 0 20 20" fill="currentColor">
                                    <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                                </svg>
                            </button>
                            <button @click="toggleHide(item)" class="text-gray-400 hover:text-gray-600 focus:outline-none" :title="item.hidden ? 'Unhide' : 'Hide'">
                                <svg v-if="item.hidden" class="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                     <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                                     <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                                </svg>
                                <svg v-else class="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21" />
                                </svg>
                           </button>
                         </div>
                    </td>
                    <td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-400">
                      {{ formatDate(item.timestamp) }}
                    </td>
                    <td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-400">
                      ${{ item.cost ? parseFloat(item.cost).toFixed(6) : '0.000000' }}
                    </td>
                    <td class="px-6 py-4 whitespace-nowrap text-sm text-gray-900 dark:text-gray-100">
                      <div class="truncate w-32" :title="item.user">{{ item.user }}</div>
                    </td>
                    <td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-400">
                      {{ item.model }}
                    </td>
                     <td class="px-6 py-4 whitespace-nowrap text-sm text-gray-900 dark:text-gray-100">
                         <input 
                            type="text" 
                            v-model="item.title" 
                            placeholder="Name Interaction"
                            @blur="updateTitle(item)"
                            @keyup.enter="$event.target.blur()"
                            class="bg-transparent border-none focus:ring-0 p-0 text-sm w-full placeholder-gray-400 font-medium text-gray-800 dark:text-gray-200"
                          />
                    </td>
                  </tr>
                </tbody>
              </table>
            </div>
          </div>
        </div>
        
        <div v-if="lastVisible" class="mt-4 flex justify-center">
            <button 
                @click="fetchInteractions" 
                :disabled="loading"
                class="inline-flex items-center px-4 py-2 border border-gray-300 dark:border-gray-600 shadow-sm text-sm font-medium rounded-md text-gray-700 dark:text-gray-200 bg-white dark:bg-gray-700 hover:bg-gray-50 dark:hover:bg-gray-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
            >
                {{ loading ? 'Loading...' : 'Load More' }}
            </button>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { db } from '../firebase';
import { collection, query, orderBy, limit, getDocs, startAfter, where, doc, updateDoc } from 'firebase/firestore';
import { formatInteractionForClipboard, copyToClipboard } from '../utils/clipboard';
import { formatDate } from '../utils/date';
import { showToast } from '../utils/toast';

export default {
  name: 'History',
  data() {
    return {
      interactions: [],
      loading: false,
      lastVisible: null,
      pageSize: 20,
      filters: {
        starredOnly: false,
        includeHidden: false,
        search: ''
      }
    }
  },
  computed: {
      filteredInteractions() {
          let result = this.interactions;

          // Client-side filtering for Hidden
          if (!this.filters.includeHidden) {
              result = result.filter(item => !item.hidden);
          }

          // Client-side filtering for Search
          if (this.filters.search) {
              const query = this.filters.search.toLowerCase();
              result = result.filter(item => 
                 (item.title && item.title.toLowerCase().includes(query)) ||
                 (item.model && item.model.toLowerCase().includes(query)) ||
                 (item.user && item.user.toLowerCase().includes(query))
              );
          }
          
          return result;
      }
  },
  watch: {
    'filters.starredOnly': function() {
        this.interactions = [];
        this.lastVisible = null;
        this.fetchInteractions();
    }
  },
  mounted() {
    this.fetchInteractions();
  },
  methods: {
    async fetchInteractions() {
      if (this.loading) return;
      this.loading = true;
      try {
        let q = query(
            collection(db, "interaction_logs"), 
            orderBy("timestamp", "desc"), 
            limit(this.pageSize)
        );

        if (this.filters.starredOnly) {
             q = query(
                collection(db, "interaction_logs"),
                where("starred", "==", true),
                orderBy("timestamp", "desc"),
                limit(this.pageSize)
            );
        }

        if (this.lastVisible) {
            if (this.filters.starredOnly) {
                 q = query(
                    collection(db, "interaction_logs"), 
                    where("starred", "==", true),
                    orderBy("timestamp", "desc"), 
                    startAfter(this.lastVisible),
                    limit(this.pageSize)
                );
            } else {
                 q = query(
                    collection(db, "interaction_logs"), 
                    orderBy("timestamp", "desc"), 
                    startAfter(this.lastVisible),
                    limit(this.pageSize)
                );
            }
        }

        const querySnapshot = await getDocs(q);
        
        if (!querySnapshot.empty) {
            this.lastVisible = querySnapshot.docs[querySnapshot.docs.length - 1];
            querySnapshot.forEach((doc) => {
                this.interactions.push({ id: doc.id, ...doc.data() });
            });
            // If we got fewer docs than page size, we reached the end
            if (querySnapshot.size < this.pageSize) {
                this.lastVisible = null;
            }
        } else {
            this.lastVisible = null;
        }

      } catch (e) {
        console.error("Error fetching history:", e);
      } finally {
        this.loading = false;
      }
    },
    formatDate,
    async copyItem(item) {
        const text = formatInteractionForClipboard(item);
        if (await copyToClipboard(text)) {
            showToast('Copied to clipboard!');
        } else {
            showToast('Failed to copy', 'error');
        }
    },
    async toggleStar(item) {
        const newValue = !item.starred;
        // Optimistic update with reactivity fix
        this.$set(item, 'starred', newValue);
        
        try {
            await updateDoc(doc(db, "interaction_logs", item.id), { starred: newValue });
        } catch (e) {
            console.error("Error toggling star:", e);
             this.$set(item, 'starred', !newValue); // Revert
        }
    },
    async toggleHide(item) {
        const newValue = !item.hidden;
        // Optimistic update with reactivity fix
        this.$set(item, 'hidden', newValue);

        try {
            await updateDoc(doc(db, "interaction_logs", item.id), { hidden: newValue });
        } catch (e) {
            console.error("Error toggling hide:", e);
             this.$set(item, 'hidden', !newValue); // Revert
        }
    },
    async updateTitle(item) {
        try {
            await updateDoc(doc(db, "interaction_logs", item.id), { title: item.title });
        } catch (e) {
            console.error("Error updating title:", e);
        }
    }
  }
}
</script>
