                                    />
                                    <div v-else class="h-16 w-16 flex items-center justify-center bg-gray-100 dark:bg-gray-600 rounded-md border border-gray-200 dark:border-gray-500 text-xs text-center p-1 overflow-hidden text-gray-900 dark:text-gray-100">
                                        {{ file.name }}
                                    </div>
                                    
                                    <button 
                                        v-if="!file.isUploading"
                                        @click="removeAttachment(index, fIndex)"
                                        class="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-0.5 hover:bg-red-600 shadow-sm opacity-0 group-hover:opacity-100 transition-opacity group-attachment:hover:opacity-100"
                                        title="Remove attachment"
                                    >
                                        <svg class="h-3 w-3" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
                                            <path fill-rule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clip-rule="evenodd" />
                                        </svg>
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>

                    <button
                        @click="removeInput(index)"
                        title="Delete input"
                        class="inline-flex items-center p-2 border border-transparent rounded-full shadow-sm text-white bg-red-600 hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500"
                        v-if="prompts.length > 1"
                    >
                        <svg class="h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" aria-hidden="true">
                            <path fill-rule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clip-rule="evenodd" />
                        </svg>
                    </button>
                </div>
            </div>
            
            <button
                @click="addInput"
                type="button"
                class="mb-4 inline-flex items-center px-3 py-2 border border-gray-300 dark:border-gray-600 shadow-sm text-sm leading-4 font-medium rounded-md text-gray-700 dark:text-gray-200 bg-white dark:bg-gray-700 hover:bg-gray-50 dark:hover:bg-gray-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
            >
                <svg class="-ml-0.5 mr-2 h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
                    <path fill-rule="evenodd" d="M10 5a1 1 0 011 1v3h3a1 1 0 110 2h-3v3a1 1 0 11-2 0v-3H6a1 1 0 110-2h3V6a1 1 0 011-1z" clip-rule="evenodd" />
                </svg>
                Add Input
            </button>
        </div>

        <button
            @click="queryLLM"
            :disabled="loading || !hasContent"
            class="mt-3 inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 disabled:opacity-50 block w-full justify-center sm:w-auto"
        >
            {{ loading ? 'Sending...' : 'Send' }}
        </button>
        <button
            @click="saveTemplate"
            class="mt-3 inline-flex items-center px-4 py-2 border border-gray-300 dark:border-gray-600 text-sm font-medium rounded-md shadow-sm text-gray-700 dark:text-gray-200 bg-white dark:bg-gray-700 hover:bg-gray-50 dark:hover:bg-gray-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 block w-full justify-center sm:w-auto sm:ml-3"
        >
            Create template
        </button>
      </div>

      <div class="mt-8 border-t border-gray-200 dark:border-gray-700 pt-4">
        <details>
            <summary class="text-sm font-medium text-gray-500 dark:text-gray-400 cursor-pointer select-none">Debug: View Payload</summary>
            <div class="mt-2 text-xs bg-gray-100 dark:bg-gray-900 dark:text-gray-300 p-2 rounded overflow-x-auto whitespace-pre-wrap" v-html="formattedPayload"></div>
        </details>
      </div>

      <div v-if="response" class="mt-6">
        <h4 class="text-md font-medium text-gray-900 dark:text-white">Response:</h4>
        <div class="mt-2 text-sm text-gray-700 dark:text-gray-300 whitespace-pre-wrap p-4 bg-gray-50 dark:bg-gray-700 rounded-md">
            {{ response }}
        </div>
        <div v-if="generationCost" class="mt-2 text-xs text-gray-500 dark:text-gray-400 text-right">
            Approx. Cost: ${{ generationCost }}
        </div>
        <div class="mt-2 text-right">
            <button
                v-if="response && currentDocId"
                @click="copyInteraction"
                class="inline-flex items-center px-3 py-1 border border-gray-300 dark:border-gray-600 shadow-sm text-xs font-medium rounded text-gray-700 dark:text-gray-200 bg-white dark:bg-gray-700 hover:bg-gray-50 dark:hover:bg-gray-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
            >
                <svg class="mr-1 h-4 w-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" />
                </svg>
                Copy Details
            </button>
        </div>
      </div>
      <div v-if="error" class="mt-4 text-sm text-red-600 dark:text-red-400">
          {{ error }}
      </div>
      
    </div>
  </div>
</template>

<script>
import { db, auth } from '../firebase';
import { doc, getDoc, collection, addDoc } from 'firebase/firestore';
import { GoogleAuthProvider, signInWithPopup } from 'firebase/auth';
import { processFile } from '../services/drive';
import { formatInteractionForClipboard, copyToClipboard } from '../utils/clipboard';

export default {
  name: 'Generate',
  props: {
    user: {
      type: Object,
      required: true
    }
  },
  data() {
    return {
      prompts: [{ id: 1, text: '', attachments: [], isDragging: false }],
      nextId: 2,
      response: '',
      loading: false,
      error: null,
      driveAccessToken: localStorage.getItem('drive_access_token'),
      generationCost: null,
      currentDocId: null,
      lastPayload: null,
      modelMeta: {},
      selectedModel: 'google/gemma-3-12b-it',
      models: [

        { id: 'google/gemma-3-4b-it', name: 'Gemma 3 4B' },
        { id: 'google/gemma-3n-e2b-it', name: 'Gemma 3n E2B IT' },
        { id: 'google/gemma-3n-e4b-it', name: 'Gemma 3n E4B IT' },
        { id: 'google/gemma-3-12b-it', name: 'Gemma 3 12B' },
        { id: 'google/gemma-3-12b-it:free', name: 'Gemma 3 12B (Free)' },
        { id: 'google/gemma-3-27b-it', name: 'Gemma 3 27B' },

        { id: 'qwen/qwen3-vl-8b-instruct', name: 'Qwen3 VL 8B Instruct' },
        { id: 'qwen/qwen3-vl-30b-a3b-instruct', name: 'Qwen3 VL 30B A3B Instruct' },
        { id: 'qwen/qwen/qwen3-vl-235b-a22b-instruct', name: 'Qwen3 VL 235B A22B Instruct' },

        { id: 'openai/gpt-3.5-turbo', name: 'GPT-3.5 Turbo' },
        { id: 'openai/gpt-4o', name: 'GPT-4o' },

        { id: 'anthropic/claude-3.5-sonnet', name: 'Claude 3.5 Sonnet' },
        { id: 'anthropic/claude-3-opus', name: 'Claude 3 Opus' },

        { id: 'google/gemini-3-flash-preview', name: 'Gemini 3 Flash Preview' },
        { id: 'google/gemini-3-pro-preview', name: 'Gemini 3 Pro Preview' },

      ]
    }
  },
  computed: {
    hasContent() {
        return this.prompts.some(p => p.text.trim().length > 0 || (p.attachments && p.attachments.length > 0));
    },
    currentModelInfo() {
        const meta = this.modelMeta[this.selectedModel];
        if (!meta) return null;
        
        const format = (p) => {
            const val = parseFloat(p) * 1000000;
            return `$${val.toFixed(2)}`;
        };
        
        return {
            pricing: {
                prompt: format(meta.pricing.prompt),
                completion: format(meta.pricing.completion)
            },
            capabilities: {
                image: meta.modalities.includes('image'),
                file: meta.modalities.includes('file') || meta.modalities.includes('pdf')
            }
        };
    },
    livePayload() {
        const contentParts = [];
        
        this.prompts.forEach(p => {
             if (p.text.trim()) {
                  contentParts.push({ type: "text", text: p.text });
              }
              if (p.attachments && p.attachments.length > 0) {
                  p.attachments.forEach(att => {
                      if (att.type === 'application/vnd.google-apps.document') {
                          contentParts.push({ 
                              type: "text", 
                              text: `[Google Doc Content: ${att.name}]` 
                          });
                      } else if (att.type.startsWith('image/')) {
                          contentParts.push({
                              type: "image_url",
                              image_url: {
                                  url: att.content // Base64
                              }
                          });
                      }
                  });
              }
        });

        if (contentParts.length === 0) return null;

        return {
            "model": this.selectedModel,
            "messages": [
              {"role": "user", "content": contentParts}
            ],
            "stream": true,
            "stream_options": { "include_usage": true }
        };
    },
    sanitizedPayload() {
        // Use livePayload if available, otherwise lastPayload (though we might not need lastPayload anymore for view)
        // Actually, let's just use livePayload for the view.
        // But wait, the user might want to see what was *actually* sent last time? 
        // The request was "update it continuously as new inputs are specified".
        // So live preview implies current state.
        
        const source = this.livePayload;
        if (!source) return null;
        
        // Deep copy to avoid mutating original
        const payload = JSON.parse(JSON.stringify(source));
        
        if (payload.messages) {
            payload.messages.forEach(msg => {
                if (Array.isArray(msg.content)) {
                    msg.content.forEach(part => {
                        if (part.image_url && part.image_url.url && part.image_url.url.startsWith('data:')) {
                            const url = part.image_url.url;
                            part.image_url.url = url.substring(0, 30) + '...[truncated base64]...' + url.substring(url.length - 10);
                        }
                    });
                }
            });
        }
        return payload;
    },
    formattedPayload() {
        if (!this.sanitizedPayload) return '';
        const json = JSON.stringify(this.sanitizedPayload, null, 2);
        // Regex to find URLs and replace with <a> tags
        return json.replace(/("url":\s*")([^"]+)(")/g, (match, p1, p2, p3) => {
            if (p2.startsWith('http')) {
                 const cleanUrl = p2.replace('&export=download', '');
                 return `${p1}<a href="${cleanUrl}" target="_blank" class="text-blue-500 hover:underline">${cleanUrl}</a>${p3}`;
            }
            return match;
        });
    }
  },
  mounted() {
    this.fetchModelInfo();
    if (this.$route.params.templateData) {
        this.restoreTemplate(this.$route.params.templateData);
    }
  },
  methods: {
    addInput() {
        this.prompts.push({ id: this.nextId++, text: '', attachments: [], isDragging: false });
    },
    removeInput(index) {
        if (this.prompts.length > 1) {
            this.prompts.splice(index, 1);
        }
    },
    removeAttachment(promptIndex, attachmentIndex) {
        this.prompts[promptIndex].attachments.splice(attachmentIndex, 1);
    },
    handleDrop(event, index) {
        this.prompts[index].isDragging = false;
        const files = event.dataTransfer.files;
        if (files.length) {
            this.processFiles(files, index);
            return;
        }

        // Try to extract image URL (from browser drag-and-drop)
        const html = event.dataTransfer.getData('text/html');
        let imageUrl = event.dataTransfer.getData('text/uri-list'); // Fallback

        if (html) {
             const parser = new DOMParser();
             const doc = parser.parseFromString(html, 'text/html');
             const img = doc.querySelector('img');
             if (img && img.src) {
                 imageUrl = img.src;
             }
        }

        if (imageUrl) {
             if (this.currentModelInfo && !this.currentModelInfo.capabilities.image) {
                 this.error = `The selected model '${this.models.find(m => m.id === this.selectedModel)?.name}' does not support image input.`;
                 setTimeout(() => { this.error = null; }, 5000);
                 return;
             }

             // Attempt to upload to Drive by converting to File
             this.urlToFile(imageUrl).then(file => {
                 if (file) {
                     this.processFiles([file], index);
                 } else {
                     // Fallback if fetch fails (e.g. CORS)
                     this.prompts[index].attachments.push({
                         name: 'Image from URL',
                         type: 'image/url',
                         content: imageUrl
                     });
                 }
             });
        }
    },
    async urlToFile(url) {
        try {
            const res = await fetch(url);
            const blob = await res.blob();
            const mime = blob.type;
            const ext = mime.split('/')[1] || 'png';
            const filename = `dropped_image_${Date.now()}.${ext}`;
            return new File([blob], filename, { type: mime });
        } catch (e) {
            console.warn("CORS or network error fetching image for upload:", e);
            return null;
        }
    },
    handlePaste(event, index) {
        const items = (event.clipboardData || event.originalEvent.clipboardData).items;
        for (const item of items) {
            if (item.kind === 'file') {
                const file = item.getAsFile();
                this.processFiles([file], index);
            }
        }
    },
    async processFiles(fileList, index) {
        if (!this.currentModelInfo) return;

        // Ensure we have a Drive Token
        if (!this.driveAccessToken) {
            const token = await this.authorizeDrive();
            if (!token) return;
        }

        for (const file of fileList) {
            const isImage = file.type.startsWith('image/');
            const supportsImage = this.currentModelInfo.capabilities.image;
            const supportsFile = this.currentModelInfo.capabilities.file;

            if (isImage && !supportsImage) {
                this.error = `The selected model '${this.models.find(m => m.id === this.selectedModel)?.name}' does not support image input.`;
                setTimeout(() => { this.error = null; }, 5000);
                continue;
            }

            if (!isImage && !supportsFile) {
                this.error = `The selected model '${this.models.find(m => m.id === this.selectedModel)?.name}' does not support file input.`;
                setTimeout(() => { this.error = null; }, 5000);
                continue;
            }

            // Add placeholder
            const tempId = Date.now() + Math.random();
            const placeholder = {
                id: tempId,
                name: file.name,
                type: file.type,
                isUploading: true
            };
            this.prompts[index].attachments.push(placeholder);

            // Set loading state
            console.log(`Starting upload for ${file.name}, tempId: ${tempId}`);
            try {
                const result = await processFile(file, this.driveAccessToken);
                console.log(`Upload finished for ${file.name}, result:`, result);
                
                // Find placeholder and replace
                const attIndex = this.prompts[index].attachments.findIndex(a => a.id === tempId);
                console.log(`Found placeholder at index: ${attIndex}`);
                
                if (attIndex !== -1) {
                    this.prompts[index].attachments.splice(attIndex, 1, {
                        id: result.id || tempId, // Keep ID stable or use Drive ID
                        name: result.name, // Hash
                        originalName: result.originalName, 
                        type: result.type,
                        content: result.webContentLink, 
                        webViewLink: result.webViewLink,
                        thumbnailLink: result.thumbnailLink,
                        isUploading: false
                    });
                    console.log("Replaced placeholder with result");
                } else {
                    console.warn("Placeholder not found!");
                }
            } catch (e) {
                console.error("Upload failed", e);
                // Remove placeholder on error
                const attIndex = this.prompts[index].attachments.findIndex(a => a.id === tempId);
                if (attIndex !== -1) {
                    this.prompts[index].attachments.splice(attIndex, 1);
                }

                // Check if error is related to permissions or auth
                const errMsg = e.message || '';
                if (errMsg.includes('403') || errMsg.includes('permission') || errMsg.includes('401') || errMsg.includes('Unauthorized')) {
                     // Force re-auth with consent
                     const token = await this.authorizeDrive(true); 
                     if (token) {
                         // Add placeholder again for retry
                         this.prompts[index].attachments.push(placeholder);
                         try {
                              // Retry upload once
                              const result = await processFile(file, token);
                              // Replace again (find by ID)
                              const retryIndex = this.prompts[index].attachments.findIndex(a => a.id === tempId);
                               if (retryIndex !== -1) {
                                    this.prompts[index].attachments.splice(retryIndex, 1, {
                                        name: result.name || result.originalName, // Ensure name is set (result.name is hash usually)
                                        originalName: result.originalName, 
                                        type: result.type,
                                        content: result.webContentLink, 
                                        webViewLink: result.webViewLink,
                                        thumbnailLink: result.thumbnailLink,
                                        isUploading: false
                                    });
                               }
                              continue;
                         } catch (retryErr) {
                             // Remove placeholder (find by ID)
                             const retryIndex = this.prompts[index].attachments.findIndex(a => a.id === tempId);
                             if (retryIndex !== -1) this.prompts[index].attachments.splice(retryIndex, 1);
                             
                             this.error = "Failed to upload file after re-auth: " + retryErr.message;
                         }
                     }
                } else {
                    this.error = "Failed to upload file: " + e.message;
                }
            }
        }
    },
    async getApiKey() {
        const userDocRef = doc(db, "allowed_users", this.user.email);
        const userDocSnap = await getDoc(userDocRef);
        
        if (!userDocSnap.exists()) {
            throw new Error("User record not found.");
        }

        const apiKey = userDocSnap.data().openrouter_api_key;
        if (!apiKey) {
            throw new Error("OpenRouter API Key not found. Please contact administrator.");
        }
        return apiKey;
    },
    async authorizeDrive(forceConsent = false) {
        const provider = new GoogleAuthProvider();
        provider.addScope('https://www.googleapis.com/auth/documents.readonly');
        provider.addScope('https://www.googleapis.com/auth/drive');
        
        if (forceConsent) {
            provider.setCustomParameters({
                prompt: 'consent'
            });
        }
        try {
            const result = await signInWithPopup(auth, provider);
            const credential = GoogleAuthProvider.credentialFromResult(result);
            this.driveAccessToken = credential.accessToken;
            localStorage.setItem('drive_access_token', credential.accessToken);
            return this.driveAccessToken;
        } catch (error) {
            console.error("Error authorizing Drive:", error);
            this.error = "Failed to authorize Google Drive access: " + error.message;
            return null;
        }
    },
    async fetchDocContent(docId) {
        if (!this.driveAccessToken) {
            const token = await this.authorizeDrive();
            if (!token) return null;
        }

        try {
            const response = await fetch(`https://docs.googleapis.com/v1/documents/${docId}`, {
                headers: {
                    'Authorization': `Bearer ${this.driveAccessToken}`
                }
            });

            if (!response.ok) {
                if (response.status === 401 || response.status === 403) {
                    // Token might be expired or invalid, try re-auth once
                    const newToken = await this.authorizeDrive();
                    if (newToken) {
                        return this.fetchDocContent(docId);
                    }
                }
                throw new Error(`Failed to fetch document: ${response.statusText}`);
            }

            const data = await response.json();
            return this.parseDocContent(data);
        } catch (e) {
            this.error = e.message;
            return null;
        }
    },
    parseDocContent(data) {
        if (!data || !data.body || !data.body.content) return [];

        const parts = [];
        let currentText = '';

        const flushText = () => {
            if (currentText.trim()) {
                parts.push({ type: 'text', content: currentText });
            }
            currentText = '';
        };

        data.body.content.forEach(element => {
            if (element.paragraph) {
                // Handle Headers
                const styleType = element.paragraph.paragraphStyle?.namedStyleType;
                let prefix = '';
                let suffix = '\n'; // Paragraph break
                
                if (styleType === 'HEADING_1') prefix = '# ';
                else if (styleType === 'HEADING_2') prefix = '## ';
                else if (styleType === 'HEADING_3') prefix = '### ';
                else if (styleType === 'HEADING_4') prefix = '#### ';
                else if (styleType === 'HEADING_5') prefix = '##### ';
                else if (styleType === 'HEADING_6') prefix = '###### ';
                
                // Handle Lists (Bullets)
                if (element.paragraph.bullet) {
                   prefix = '- ' + prefix;
                }

                currentText += prefix;

                element.paragraph.elements.forEach(el => {
                    if (el.textRun && el.textRun.content) {
                        let content = el.textRun.content;
                        const style = el.textRun.textStyle;
                        
                        // Handle Bold/Italic
                        // Note: This simple approach handles nested styles poorly (e.g. bold+italic), 
                        // but is sufficient for basic formatting.
                        if (style) {
                            if (style.bold && content.trim()) content = `**${content}**`;
                            if (style.italic && content.trim()) content = `*${content}*`;
                        }
                        
                        currentText += content;
                    } else if (el.inlineObjectElement) {
                        // Flush text before image
                        flushText();
                        
                        const objectId = el.inlineObjectElement.inlineObjectId;
                        const embeddedObject = data.inlineObjects[objectId]?.inlineObjectProperties?.embeddedObject;
                        
                        // Extract Image URL
                        // Note: embeddedObject.imageProperties.contentUri is valid for ~30mins
                        if (embeddedObject && embeddedObject.imageProperties && embeddedObject.imageProperties.contentUri) {
                             parts.push({
                                 type: 'image',
                                 source: embeddedObject.imageProperties.contentUri,
                                 name: 'Embedded Image' // Could try to get title if available
                             });
                        }
                    }
                });
                
                currentText += suffix;
            }
        });
        
        flushText();
        
        return parts;
    },
    async fetchDocMetadata(docId) {
        if (!this.driveAccessToken) {
           // Wait for auth or just return null (UI will handle missing metadata)
           return null;
        }
        
        try {
            const response = await fetch(`https://www.googleapis.com/drive/v3/files/${docId}?fields=name,owners,modifiedTime,webViewLink`, {
                headers: {
                    'Authorization': `Bearer ${this.driveAccessToken}`
                }
            });

            if (!response.ok) {
                 console.error("Failed to fetch doc metadata", response.statusText);
                 return null;
            }

            return await response.json();
        } catch (e) {
            console.error("Error fetching metadata:", e);
            return null;
        }
    },
    async checkForDocLinks(index, event) {
        // Use event value if available, otherwise fall back to model
        const text = event && event.target ? event.target.value : this.prompts[index].text;
        
        if (!text) return;

        const googleDocRegex = /https:\/\/docs\.google\.com\/document\/d\/([a-zA-Z0-9-_]+)[^ \n]*/g;
        let match;
        
        const matches = [];
        googleDocRegex.lastIndex = 0;
        
        while ((match = googleDocRegex.exec(text)) !== null) {
            matches.push({
                full: match[0],
                id: match[1],
                index: match.index
            });
        }

        if (matches.length > 0) {
            // First match wins for "only content of that chunk" rule? 
            // The user said "When a google doc is pasted, it should be the only content of that chunk"
            // So if we find a link, we replace the whole text? Or just that link?
            // "the textarea should disappear and be replaced with a clickable URL" implies the chunk becomes a "Doc Chunk"
            
            // We'll take the first match, clear the text, and add the attachment with metadata.
            const m = matches[0];
            
            // Fetch metadata
            if (!this.driveAccessToken) {
                 // Try to auth internally or just wait? 
                 // If we auto-auth here, it might popup. But user just pasted.
                 // Let's try to get token if possible, or trigger auth flow if needed?
                 // For now, assume token exists or will be refreshed. The user is logged in.
            }

            const metadata = await this.fetchDocMetadata(m.id);
            
            this.prompts[index].text = ''; // Clear text as requested
            this.prompts[index].attachments = [{ // Replace any existing attachments? "only content"
                name: metadata ? metadata.name : 'Google Doc',
                type: 'application/vnd.google-apps.document',
                docId: m.id,
                content: null,
                metadata: metadata // Store full metadata
            }];
        }
    },
    async fetchModelInfo() {
        try {
            const apiKey = await this.getApiKey();
            const res = await fetch("https://openrouter.ai/api/v1/models", {
                headers: {
                    "Authorization": `Bearer ${apiKey}`
                }
            });
            
            if (res.ok) {
                const data = await res.json();
                const meta = {};
                data.data.forEach(m => {
                    meta[m.id] = {
                        pricing: m.pricing,
                        modalities: m.architecture?.input_modalities || []
                    };
                });
                this.modelMeta = meta;
            }
        } catch (e) {
            console.error("Failed to fetch model info", e);
        }
    },
    async queryLLM() {
      if (!this.hasContent) return;

      this.loading = true;
      this.error = null;
      this.response = '';
      this.generationCost = null;
      this.currentDocId = null;
      
      const contentParts = [];
      
      try {
          // Process all prompts and attachments
          for (const p of this.prompts) {
              if (p.text.trim()) {
                  contentParts.push({ type: "text", text: p.text });
              }
              if (p.attachments && p.attachments.length > 0) {
                  for (const att of p.attachments) {
                      if (att.type === 'application/vnd.google-apps.document') {
                          // Fetch doc content (now returns an array of parts)
                          const docParts = await this.fetchDocContent(att.docId);
                          
                          if (docParts && docParts.length > 0) {
                              
                              docParts.forEach(part => {
                                  if (part.type === 'text') {
                                      contentParts.push({ type: "text", text: part.content });
                                  } else if (part.type === 'image') {
                                      contentParts.push({
                                          type: "image_url",
                                          image_url: {
                                              url: part.source // Google Drive/Docs Image URI
                                          }
                                      });
                                  }
                              });

                              /*
                              contentParts.push({ 
                                  type: "text", 
                                  text: `\n[End of Google Doc]\n` 
                              });
                              */
                          } else {
                               if (this.error) throw new Error(this.error);
                          }
                      } else if (att.type.startsWith('image/')) {
                          contentParts.push({
                              type: "image_url",
                              image_url: {
                                  url: att.content // Base64
                              }
                          });
                      } else {
                          // Generic file, maybe text? 
                          // For now, only supporting text if we can read it, but here we only have base64.
                          // OpenRouter might not support 'file' type directly unless using specific endpoints.
                          // But typically we don't send raw files as image_url unless it's an image.
                          // If it's a PDF, some models support it? 
                          // For now, only images and docs are handled explicitly.
                      }
                  }
              }
          }
          
          if (contentParts.length === 0) return;

        // 1. Get API Key
        const apiKey = await this.getApiKey();

        // 2. Make Request
        const requestBody = {
            "model": this.selectedModel,
            "messages": [
              {"role": "user", "content": contentParts}
            ],
            "stream": true,
            "stream_options": { "include_usage": true }
        };
        this.lastPayload = requestBody;

        const res = await fetch("https://openrouter.ai/api/v1/chat/completions", {
          method: "POST",
          headers: {
            "Authorization": `Bearer ${apiKey}`,
            "Content-Type": "application/json"
          },
          body: JSON.stringify(requestBody)
        });

        if (!res.ok) {
            const errData = await res.json();
            throw new Error(errData.error?.message || "Failed to fetch response from OpenRouter");
        }

        // 3. Handle Stream
        const reader = res.body.getReader();
        const decoder = new TextDecoder("utf-8");

        for (;;) {
          const { done, value } = await reader.read();
          if (done) break;
          
          const chunk = decoder.decode(value);
          const lines = chunk.split("\n");
          
          for (const line of lines) {
            if (line.startsWith("data: ")) {
                const dataStr = line.slice(6);
                if (dataStr === "[DONE]") continue;
                try {
                    const data = JSON.parse(dataStr);
                    
                    // Handle Content
                    const content = data.choices[0]?.delta?.content || "";
                    this.response += content;
                    
                    // Handle Usage
                    if (data.usage) {
                        const promptTokens = data.usage.prompt_tokens || 0;
                        const completionTokens = data.usage.completion_tokens || 0;
                        const pricing = this.modelMeta[this.selectedModel]?.pricing;
                        
                        if (pricing) {
                            const promptCost = promptTokens * parseFloat(pricing.prompt);
                            const completionCost = completionTokens * parseFloat(pricing.completion);
                            this.generationCost = (promptCost + completionCost).toFixed(6);
                        }
                    }
                } catch (e) {
                    // console.error("Error parsing stream chunk", e);
                }
            }
          }
        }

        // 4. Log to Firebase
        try {
            const docRef = await addDoc(collection(db, "interaction_logs"), {
                timestamp: new Date(),
                user: this.user.email,
                payload: this.sanitizedPayload, // Uses the computed property (truncated base64)
                response: this.response,
                cost: this.generationCost ? parseFloat(this.generationCost) : 0,
                model: this.selectedModel
            });
            this.currentDocId = docRef.id;
        } catch (e) {
            console.error("Failed to log interaction", e);
        }

      } catch (err) {
        this.error = err.message;
      } finally {
        this.loading = false;
      }
    },
    async copyInteraction() {
        if (!this.response || !this.currentDocId) return;
        
        const interaction = {
            id: this.currentDocId,
            timestamp: new Date(), // Using current time as approximation for just-generated content
            model: this.selectedModel,
            response: this.response
        };
        
        const text = formatInteractionForClipboard(interaction);
        const success = await copyToClipboard(text);
        if (success) {
            alert('Copied to clipboard!');
        }
    },
    async saveTemplate() {
        const name = prompt("Enter a name for this template:");
        if (!name) return;
        
        try {
            const rawPrompts = this.prompts.map(p => ({
                text: p.text,
                attachments: p.attachments.map(a => ({
                    name: a.name,
                    originalName: a.originalName,
                    type: a.type,
                    docId: a.docId,
                    metadata: a.metadata,
                    content: a.content,
                    webViewLink: a.webViewLink,
                    thumbnailLink: a.thumbnailLink
                }))
            }));

            // Remove undefined values which Firestore doesn't support
            const templatePrompts = JSON.parse(JSON.stringify(rawPrompts));

            await addDoc(collection(db, "templates"), {
                name: name,
                creator: this.user.email,
                createdAt: new Date(),
                model: this.selectedModel,
                prompts: templatePrompts
            });
            
            alert("Template saved successfully!");
        } catch (e) {
            console.error("Error saving template:", e);
            this.error = "Failed to save template: " + e.message;
        }
    },
    async restoreTemplate(data) {
        this.selectedModel = data.model;
        this.prompts = data.prompts.map((p, i) => ({
            id: i + 1,
            text: p.text,
            attachments: p.attachments || [],
            isDragging: false
        }));
        this.nextId = this.prompts.length + 1;

        // Restore/Fetch metadata for Google Docs
        for (const p of this.prompts) {
            if (p.attachments) {
                for (const att of p.attachments) {
                    if (att.type === 'application/vnd.google-apps.document' && att.docId) {
                        // Use existing metadata or fetch if missing (backward compatibility)
                        if (!att.metadata) {
                             const meta = await this.fetchDocMetadata(att.docId);
                             if (meta) {
                                 // Reactively set metadata
                                 this.$set(att, 'metadata', meta);
                             }
                        }
                    }
                }
            }
        }
    }
  }
}
